9	import {ActivationEnd, ChildActivationEnd, Event} from '../events';
10	import type {DetachedRouteHandleInternal, RouteReuseStrategy} from '../route_reuse_strategy';
11	import type {ChildrenOutletContexts} from '../router_outlet_context';
12	import {ActivatedRoute, advanceActivatedRoute, RouterState} from '../router_state';
13	import {nodeChildrenAsMap, TreeNode} from '../utils/tree';
14	
15	let warnedAboutUnsupportedInputBinding = false;
16	export class ActivateRoutes {
17	  constructor(
18	    private routeReuseStrategy: RouteReuseStrategy,
19	    private futureState: RouterState,
20	    private currState: RouterState,
21	    private forwardEvent: (evt: Event) => void,
22	    private inputBindingEnabled: boolean,
23	  ) {}
24	
25	  activate(parentContexts: ChildrenOutletContexts): void {
26	    const futureRoot = this.futureState._root;
27	    const currRoot = this.currState ? this.currState._root : null;
28	
29	    this.deactivateChildRoutes(futureRoot, currRoot, parentContexts);
30	    advanceActivatedRoute(this.futureState.root);
31	    this.activateChildRoutes(futureRoot, currRoot, parentContexts);
32	  }
33	
34	  // De-activate the child route that are not re-used for the future state
35	  private deactivateChildRoutes(
36	    futureNode: TreeNode<ActivatedRoute>,
37	    currNode: TreeNode<ActivatedRoute> | null,
38	    contexts: ChildrenOutletContexts,
39	  ): void {
40	    const children: {[outletName: string]: TreeNode<ActivatedRoute>} = nodeChildrenAsMap(currNode);
41	
42	    // Recurse on the routes active in the future state to de-activate deeper children
43	    futureNode.children.forEach((futureChild) => {
44	      const childOutletName = futureChild.value.outlet;
45	      this.deactivateRoutes(futureChild, children[childOutletName], contexts);
46	      delete children[childOutletName];
47	    });
48	
49	    // De-activate the routes that will not be re-used
50	    Object.values(children).forEach((v: TreeNode<ActivatedRoute>) => {
51	      this.deactivateRouteAndItsChildren(v, contexts);
52	    });
53	  }
54	
55	  private deactivateRoutes(
56	    futureNode: TreeNode<ActivatedRoute>,
57	    currNode: TreeNode<ActivatedRoute>,
58	    parentContext: ChildrenOutletContexts,
59	  ): void {
60	    const future = futureNode.value;
61	    const curr = currNode ? currNode.value : null;
62	
63	    if (future === curr) {
64	      // Reusing the node, check to see if the children need to be de-activated
65	      if (future.component) {
66	        // If we have a normal route, we need to go through an outlet.
67	        const context = parentContext.getContext(future.outlet);
68	        if (context) {
69	          this.deactivateChildRoutes(futureNode, currNode, context.children);
70	        }
71	      } else {
72	        // if we have a componentless route, we recurse but keep the same outlet map.
73	        this.deactivateChildRoutes(futureNode, currNode, parentContext);
74	      }
75	    } else {
76	      if (curr) {
77	        // Deactivate the current route which will not be re-used
78	        this.deactivateRouteAndItsChildren(currNode, parentContext);
79	      }
80	    }
81	  }
82	
83	  private deactivateRouteAndItsChildren(
84	    route: TreeNode<ActivatedRoute>,
85	    parentContexts: ChildrenOutletContexts,
86	  ): void {
87	    // If there is no component, the Route is never attached to an outlet (because there is no
88	    // component to attach).
89	    if (route.value.component && this.routeReuseStrategy.shouldDetach(route.value.snapshot)) {
90	      this.detachAndStoreRouteSubtree(route, parentContexts);
91	    } else {
92	      this.deactivateRouteAndOutlet(route, parentContexts);
93	    }
94	  }
95	
96	  private detachAndStoreRouteSubtree(
97	    route: TreeNode<ActivatedRoute>,
98	    parentContexts: ChildrenOutletContexts,
99	  ): void {
100	    const context = parentContexts.getContext(route.value.outlet);
101	    const contexts = context && route.value.component ? context.children : parentContexts;
102	    const children: {[outletName: string]: TreeNode<ActivatedRoute>} = nodeChildrenAsMap(route);
103	
104	    for (const treeNode of Object.values(children)) {
105	      this.deactivateRouteAndItsChildren(treeNode, contexts);
106	    }
107	
108	    if (context && context.outlet) {
109	      const componentRef = context.outlet.detach();
110	      const contexts = context.children.onOutletDeactivated();
111	      this.routeReuseStrategy.store(route.value.snapshot, {componentRef, route, contexts});
112	    }
113	  }
114	
115	  private deactivateRouteAndOutlet(
116	    route: TreeNode<ActivatedRoute>,
117	    parentContexts: ChildrenOutletContexts,
118	  ): void {
119	    const context = parentContexts.getContext(route.value.outlet);
120	    // The context could be `null` if we are on a componentless route but there may still be
121	    // children that need deactivating.
122	    const contexts = context && route.value.component ? context.children : parentContexts;
123	    const children: {[outletName: string]: TreeNode<ActivatedRoute>} = nodeChildrenAsMap(route);
124	
125	    for (const treeNode of Object.values(children)) {
126	      this.deactivateRouteAndItsChildren(treeNode, contexts);
127	    }
128	
129	    if (context) {
130	      if (context.outlet) {
131	        // Destroy the component
132	        context.outlet.deactivate();
133	        // Destroy the contexts for all the outlets that were in the component
134	        context.children.onOutletDeactivated();
135	      }
136	      // Clear the information about the attached component on the context but keep the reference to
137	      // the outlet. Clear even if outlet was not yet activated to avoid activating later with old
138	      // info
139	      context.attachRef = null;
140	      context.route = null;
141	    }
142	    // Destroy `_localInjector` here when the route is
143	    // unmounted by the Router. This method (`deactivateRouteAndOutlet`) is
144	    // skipped when a route is being detached for `RouteReuseStrategy`, preserving
145	    // its injector. Those preserved injectors are eventually managed and destroyed
146	    // manually via `destroyDetachedRouteHandle()` or if the route is deactivated later rather than detached.
147	    route.value._localInjector?.destroy();
148	  }
149	
150	  private activateChildRoutes(
151	    futureNode: TreeNode<ActivatedRoute>,
152	    currNode: TreeNode<ActivatedRoute> | null,
153	    contexts: ChildrenOutletContexts,
154	  ): void {
155	    const children: {[outlet: string]: TreeNode<ActivatedRoute>} = nodeChildrenAsMap(currNode);
156	    futureNode.children.forEach((c) => {
157	      this.activateRoutes(c, children[c.value.outlet], contexts);
158	      this.forwardEvent(new ActivationEnd(c.value.snapshot));
159	    });
160	    if (futureNode.children.length) {
161	      this.forwardEvent(new ChildActivationEnd(futureNode.value.snapshot));
162	    }
163	  }
164	
165	  private activateRoutes(
166	    futureNode: TreeNode<ActivatedRoute>,
167	    currNode: TreeNode<ActivatedRoute>,
168	    parentContexts: ChildrenOutletContexts,
169	  ): void {
170	    const future = futureNode.value;
171	    const curr = currNode ? currNode.value : null;
172	
173	    advanceActivatedRoute(future);
174	
175	    // reusing the node
176	    if (future === curr) {
177	      if (future.component) {
178	        // If we have a normal route, we need to go through an outlet.
179	        const context = parentContexts.getOrCreateContext(future.outlet);
180	        this.activateChildRoutes(futureNode, currNode, context.children);
181	      } else {
182	        // if we have a componentless route, we recurse but keep the same outlet map.
183	        this.activateChildRoutes(futureNode, currNode, parentContexts);
184	      }
185	    } else {
186	      if (future.component) {
187	        // if we have a normal route, we need to place the component into the outlet and recurse.
188	        const context = parentContexts.getOrCreateContext(future.outlet);
189	
190	        if (this.routeReuseStrategy.shouldAttach(future.snapshot)) {
191	          const stored = <DetachedRouteHandleInternal>(
192	            this.routeReuseStrategy.retrieve(future.snapshot)
193	          );
194	          this.routeReuseStrategy.store(future.snapshot, null);
195	          context.children.onOutletReAttached(stored.contexts);
196	          context.attachRef = stored.componentRef;
197	          context.route = stored.route.value;
198	          if (context.outlet) {
199	            // Attach right away when the outlet has already been instantiated
200	            // Otherwise attach from `RouterOutlet.ngOnInit` when it is instantiated
201	            context.outlet.attach(stored.componentRef, stored.route.value);
202	          }
203	
204	          advanceActivatedRoute(stored.route.value);
205	          this.activateChildRoutes(futureNode, null, context.children);
206	        } else {
207	          context.attachRef = null;
208	          context.route = future;
209	          if (context.outlet) {
210	            // Activate the outlet when it has already been instantiated
211	            // Otherwise it will get activated from its `ngOnInit` when instantiated
212	            context.outlet.activateWith(future, context.injector);
213	          }
214	
215	          this.activateChildRoutes(futureNode, null, context.children);
216	        }
217	      } else {
218	        // if we have a componentless route, we recurse but keep the same outlet map.
219	        this.activateChildRoutes(futureNode, null, parentContexts);
220	      }
221	    }
222	    if (typeof ngDevMode === 'undefined' || ngDevMode) {
223	      const context = parentContexts.getOrCreateContext(future.outlet);
224	      const outlet = context.outlet;
225	      if (
226	        outlet &&
227	        this.inputBindingEnabled &&
228	        !outlet.supportsBindingToComponentInputs &&
229	        !warnedAboutUnsupportedInputBinding
230	      ) {
231	        console.warn(
232	          `'withComponentInputBinding' feature is enabled but ` +
233	            `this application is using an outlet that may not support binding to component inputs.`,
234	        );
235	        warnedAboutUnsupportedInputBinding = true;
236	      }
237	    }
238	  }
239	}
