4	 *
5	 * Use of this source code is governed by an MIT-style license that can be
6	 * found in the LICENSE file at https://angular.dev/license
7	 */
8	
9	import {ComponentRef, inject, Service} from '@angular/core';
10	
11	import {Route} from './models';
12	import {OutletContext} from './router_outlet_context';
13	import {ActivatedRoute, ActivatedRouteSnapshot} from './router_state';
14	import {TreeNode} from './utils/tree';
15	
16	/**
17	 * @description
18	 *
19	 * Represents the detached route tree.
20	 *
21	 * This is an opaque value the router will give to a custom route reuse strategy
22	 * to store and retrieve later on.
23	 *
24	 * @publicApi
25	 */
26	export type DetachedRouteHandle = {};
27	
28	/** @internal */
29	export type DetachedRouteHandleInternal = {
30	  contexts: Map<string, OutletContext>;
31	  componentRef: ComponentRef<any>;
32	  route: TreeNode<ActivatedRoute>;
33	};
34	
35	/**
36	 * @description
37	 *
38	 * Destroys the component associated with a `DetachedRouteHandle`.
39	 *
40	 * This function should be used when a `RouteReuseStrategy` decides to drop a stored handle
41	 * and wants to ensure that the component is destroyed.
42	 *
43	 * @param handle The detached route handle to destroy.
44	 *
45	 * @publicApi
46	 * @see [Manually destroying detached route handles](guide/routing/customizing-route-behavior#manually-destroying-detached-route-handles)
47	 */
48	export function destroyDetachedRouteHandle(handle: DetachedRouteHandle): void {
49	  const internalHandle = handle as DetachedRouteHandleInternal;
50	  if (internalHandle && internalHandle.componentRef) {
51	    internalHandle.componentRef.destroy();
52	    // It is critical to destroy the `_localInjector` here. When a route is detached
53	    // by the `RouteReuseStrategy`, the `_localInjector` is retained because the
54	    // ActivatedRoute object is stored and can be attached later.
55	    // When the developer drops the handle (e.g., deciding not to reuse it),
56	    // they must manually invoke `destroyDetachedRouteHandle` to prevent a memory leak.
57	    internalHandle.route.value._localInjector?.destroy();
58	  }
59	}
60	
61	export interface ExperimentalRouteReuseStrategy {
62	  shouldDestroyInjector?(route: Route): boolean;
63	  retrieveStoredRouteHandles?(): Array<DetachedRouteHandleInternal>;
64	}
65	
66	/**
67	 * @description
68	 *
69	 * Provides a way to customize when activated routes get reused.
70	 *
71	 * @publicApi
72	 */
73	@Service({factory: () => inject(DefaultRouteReuseStrategy)})
74	export abstract class RouteReuseStrategy {
75	  /** Determines if this route (and its subtree) should be detached to be reused later */
76	  abstract shouldDetach(route: ActivatedRouteSnapshot): boolean;
77	
78	  /**
79	   * Stores the detached route.
80	   *
81	   * Storing a `null` value should erase the previously stored value.
82	   */
83	  abstract store(route: ActivatedRouteSnapshot, handle: DetachedRouteHandle | null): void;
84	
85	  /** Determines if this route (and its subtree) should be reattached */
86	  abstract shouldAttach(route: ActivatedRouteSnapshot): boolean;
87	
88	  /** Retrieves the previously stored route */
89	  abstract retrieve(route: ActivatedRouteSnapshot): DetachedRouteHandle | null;
90	
91	  /** Determines if a route should be reused */
92	  abstract shouldReuseRoute(future: ActivatedRouteSnapshot, curr: ActivatedRouteSnapshot): boolean;
93	}
94	
95	/**
96	 * @description
97	 *
98	 * This base route reuse strategy only reuses routes when the matched router configs are
99	 * identical. This prevents components from being destroyed and recreated
100	 * when just the route parameters, query parameters or fragment change
101	 * (that is, the existing component is _reused_).
102	 *
103	 * This strategy does not store any routes for later reuse.
104	 *
105	 * Angular uses this strategy by default.
106	 *
107	 *
108	 * It can be used as a base class for custom route reuse strategies, i.e. you can create your own
109	 * class that extends the `BaseRouteReuseStrategy` one.
110	 * @publicApi
111	 */
112	export abstract class BaseRouteReuseStrategy implements RouteReuseStrategy {
113	  /**
114	   * Whether the given route should detach for later reuse.
115	   * Always returns false for `BaseRouteReuseStrategy`.
116	   * */
117	  shouldDetach(route: ActivatedRouteSnapshot): boolean {
118	    return false;
119	  }
120	
121	  /**
122	   * A no-op; the route is never stored since this strategy never detaches routes for later re-use.
123	   */
124	  store(route: ActivatedRouteSnapshot, detachedTree: DetachedRouteHandle): void {}
125	
126	  /** Returns `false`, meaning the route (and its subtree) is never reattached */
127	  shouldAttach(route: ActivatedRouteSnapshot): boolean {
128	    return false;
129	  }
130	
131	  /** Returns `null` because this strategy does not store routes for later re-use. */
132	  retrieve(route: ActivatedRouteSnapshot): DetachedRouteHandle | null {
133	    return null;
134	  }
135	
136	  /**
137	   * Determines if a route should be reused.
138	   * This strategy returns `true` when the future route config and current route config are
139	   * identical.
140	   */
141	  shouldReuseRoute(future: ActivatedRouteSnapshot, curr: ActivatedRouteSnapshot): boolean {
142	    return future.routeConfig === curr.routeConfig;
143	  }
144	
145	  /**
146	   * Determines if the injector for the given route should be destroyed.
147	   *
148	   * This method is called by the router when the `RouteReuseStrategy` is destroyed.
149	   * If this method returns `true`, the router will destroy the injector for the given route.
150	   *
151	   * @see {@link withExperimentalAutoCleanupInjectors}
152	   * @xperimental 21.1
153	   */
154	  shouldDestroyInjector(route: Route): boolean {
155	    return true;
156	  }
157	}
158	
159	@Service()
160	export class DefaultRouteReuseStrategy extends BaseRouteReuseStrategy {}
