19	/**
20	 * Represents the state of the router as a tree of activated routes.
21	 *
22	 * @usageNotes
23	 *
24	 * Every node in the route tree is an `ActivatedRoute` instance
25	 * that knows about the "consumed" URL segments, the extracted parameters,
26	 * and the resolved data.
27	 * Use the `ActivatedRoute` properties to traverse the tree from any node.
28	 *
29	 * The following fragment shows how a component gets the root node
30	 * of the current state to establish its own route tree:
31	 *
32	 * ```ts
33	 * @Component({templateUrl:'template.html'})
34	 * class MyComponent {
35	 *   constructor(router: Router) {
36	 *     const state: RouterState = router.routerState;
37	 *     const root: ActivatedRoute = state.root;
38	 *     const child = root.firstChild;
39	 *     const id: Observable<string> = child.params.map(p => p.id);
40	 *     //...
41	 *   }
42	 * }
43	 * ```
44	 *
45	 * @see {@link ActivatedRoute}
46	 * @see [Getting route information](guide/routing/common-router-tasks#getting-route-information)
47	 *
48	 * @publicApi
49	 */
50	export class RouterState extends Tree<ActivatedRoute> {
51	  /** @internal */
52	  constructor(
53	    root: TreeNode<ActivatedRoute>,
54	    /** The current snapshot of the router state */
55	    public snapshot: RouterStateSnapshot,
56	  ) {
57	    super(root);
58	    setRouterState(<RouterState>this, root);
59	  }
60	
61	  override toString(): string {
62	    return this.snapshot.toString();
63	  }
64	}
65	
66	export function createEmptyState(
67	  rootComponent: Type<any> | null,
68	  injector: EnvironmentInjector,
69	): RouterState {
70	  const snapshot = createEmptyStateSnapshot(rootComponent, injector);
71	  const emptyUrl = new BehaviorSubject([new UrlSegment('', {})]);
72	  const emptyParams = new BehaviorSubject({});
73	  const emptyData = new BehaviorSubject({});
74	  const emptyQueryParams = new BehaviorSubject({});
75	  const fragment = new BehaviorSubject<string | null>('');
76	  const activated = new ActivatedRoute(
77	    emptyUrl,
78	    emptyParams,
79	    emptyQueryParams,
80	    fragment,
81	    emptyData,
82	    PRIMARY_OUTLET,
83	    rootComponent,
84	    snapshot.root,
85	  );
86	  activated.snapshot = snapshot.root;
87	  return new RouterState(new TreeNode<ActivatedRoute>(activated, []), snapshot);
88	}
89	
90	export function createEmptyStateSnapshot(
91	  rootComponent: Type<any> | null,
92	  injector: EnvironmentInjector,
93	): RouterStateSnapshot {
94	  const emptyParams = {};
95	  const emptyData = {};
96	  const emptyQueryParams = {};
97	  const fragment = '';
98	  const activated = new ActivatedRouteSnapshot(
99	    [],
100	    emptyParams,
101	    emptyQueryParams,
102	    fragment,
103	    emptyData,
104	    PRIMARY_OUTLET,
105	    rootComponent,
106	    null,
107	    {},
108	    injector,
109	  );
110	  return new RouterStateSnapshot('', new TreeNode<ActivatedRouteSnapshot>(activated, []));
111	}
112	
113	/**
114	 * Provides access to information about a route associated with a component
115	 * that is loaded in an outlet.
116	 * Use to traverse the `RouterState` tree and extract information from nodes.
117	 *
118	 * The following example shows how to construct a component using information from a
119	 * currently activated route.
120	 *
121	 * Note: the observables in this class only emit when the current and previous values differ based
122	 * on shallow equality. For example, changing deeply nested properties in resolved `data` will not
123	 * cause the `ActivatedRoute.data` `Observable` to emit a new value.
124	 *
125	 * {@example router/activated-route/activated_route_component.ts region="activated-route"}
126	 *
127	 * @see [Getting route information](guide/routing/common-router-tasks#getting-route-information)
128	 *
129	 * @publicApi
130	 */
131	export class ActivatedRoute {
132	  /** The current snapshot of this route */
133	  snapshot!: ActivatedRouteSnapshot;
134	  /** @internal */
135	  _futureSnapshot: ActivatedRouteSnapshot;
136	  /** @internal */
137	  _routerState!: RouterState;
138	  /** @internal */
139	  _paramMap?: Observable<ParamMap>;
140	  /** @internal */
141	  _queryParamMap?: Observable<ParamMap>;
142	
143	  /** An Observable of the resolved route title */
144	  readonly title: Observable<string | undefined>;
145	
146	  /** An observable of the URL segments matched by this route. */
147	  public url: Observable<UrlSegment[]>;
148	  /** An observable of the matrix parameters scoped to this route. */
149	  public params: Observable<Params>;
150	  /** An observable of the query parameters shared by all the routes. */
151	  public queryParams: Observable<Params>;
152	  /** An observable of the URL fragment shared by all the routes. */
153	  public fragment: Observable<string | null>;
154	  /** An observable of the static and resolved data of this route. */
155	  public data: Observable<Data>;
156	
157	  /**
158	   * Injector scoped to the lifetime of this ActivatedRoute object.
159	   * Created only when features tied to ActivatedRoute lifetime are used.
160	   *
161	   * @internal
162	   */
163	  _localInjector?: EnvironmentInjector;
164	
165	  /** @internal */
166	  constructor(
167	    /** @internal */
168	    public urlSubject: BehaviorSubject<UrlSegment[]>,
169	    /** @internal */
170	    public paramsSubject: BehaviorSubject<Params>,
171	    /** @internal */
172	    public queryParamsSubject: BehaviorSubject<Params>,
173	    /** @internal */
174	    public fragmentSubject: BehaviorSubject<string | null>,
175	    /** @internal */
176	    public dataSubject: BehaviorSubject<Data>,
177	    /** The outlet name of the route, a constant. */
